import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.next();

        int bufferSize = 10;
        char[] buffer = new char[bufferSize];
        int i = 0;

        for (char c : name.toCharArray()) {
            if (i < bufferSize) {
                buffer[i++] = c;
            } else {
                break; // Prevent buffer overflow by breaking if buffer size is reached
            }
        }

        System.out.println("Your name is: " + new String(buffer, 0, i)); // Output only up to valid characters
    }
}

### Explanation:
취약유형: Buffer Overflow
